from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core

class PrismGetProductVersionsNode(BaseNode):
    name = "Prism: Get Product Versions"
    category = "DCCs"

    def __init__(self):
        super().__init__(use_exec=False)
        self.icon_path = "icons/prism_icon.png"
        self.add_input("core", "any")
        self.add_input("product", "any")
        self.add_output("versions", "list")
        self.add_output("latest_version", "any")
        self.add_output("count", "int")

    async def execute(self, inputs):
        core = resolve_prism_core(inputs)
        product = inputs.get('product')
        if core is None or product is None:
            self.log_error("No PrismCore or product provided.")
            return {'versions': [], 'latest_version': None, 'count': 0}
        try:
            versions = []
            for attr in ('getVersionsFromProduct', 'getProductVersions', 'getVersions'):
                if hasattr(core.products, attr):
                    versions = getattr(core.products, attr)(product) or []
                    break
            versions = list(versions)
            latest = versions[-1] if versions else None
            self.log_info(f"Found {len(versions)} version(s).")
            return {'versions': versions, 'latest_version': latest, 'count': len(versions)}
        except Exception as e:
            self.log_error(f"getVersionsFromProduct failed: {e}")
            return {'versions': [], 'latest_version': None, 'count': 0}

def register_node():
    return PrismGetProductVersionsNode
